+/// Result of markdown detection analysis.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub struct MarkdownDetection {
+    /// Number of markdown indicators found.
+    pub indicators: u8,
+    /// Whether the text appears to be markdown (2+ indicators).
